import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F13: 資本支出效能與股利防禦","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F13_資本支出效能與股利防禦.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F13_資本支出效能與股利防禦.md"}'),l={name:"審計報告庫/財務審計/6442_光聖/20260504/F13_資本支出效能與股利防禦.md"};function i(n,a,h,s,d,p){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="f13-資本支出效能與股利防禦" tabindex="-1">F13: 資本支出效能與股利防禦 <a class="header-anchor" href="#f13-資本支出效能與股利防禦" aria-label="Permalink to &quot;F13: 資本支出效能與股利防禦&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>資本支出 (CapEx) 的投入效能為何？自由現金流 (FCF) 是否足以支撐其股利政策？是否存在「借債配息」之虛耗現象？</p><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CapEx 投入 7.46 億創造營收年增 54.2 億（回報率 7.3 倍），FCF 25.9 億完全覆蓋現金股利 6.5 億，無借債配息壓力，股利安全邊際極高且覆蓋率充足。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：2025 年報</li></ul><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>CapEx/營收比 14.8%→14.1%→3.0%，2025 年降至維護性水準。FCF 從 1.89 億→8.24 億→25.9 億，CAGR 270%。股利發放：112 年 2.1 元→113 年 8.62 元（+310%），配息率約 37%。FCF 覆蓋股利 5.6 倍，即使 2026 年獲利下滑 30%，FCF 仍足以支撐現有股利水準。</p><p><strong>評級：S（優）</strong> — CapEx 回報驚人，股利安全邊際極高。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>CapEx 回報率：</strong> 2024 年 CapEx 7.46 億→2025 年營收增加 54.2 億，增量營收/CapEx 比率達 7.3 倍。這意味著每投入 1 元 CapEx 可創造 7.3 元年營收增量，在製造業屬頂尖水準。菲律賓廠從動工到投產僅約 18 個月，執行力極強。</p><p><strong>配息安全性：</strong> FCF 25.9 億 vs 股利總額約 6.5 億（8.62 元 × 約 7,580 萬股），FCF 覆蓋率 398%。CFO 29.1 億 / 股利 6.5 億 = 4.5 倍。即使營收衰退 30%，CFO 保守估計仍有 15-18 億，仍可覆蓋股利 2.5 倍以上。</p><p><strong>股利穩定性測試：</strong> 模擬獲利下滑 20%（EPS 從 23.46→18.77），配息率若維持 37%，現金股利約 6.94 元。FCF 在營收衰退情境下約 17-18 億，仍完全覆蓋。</p><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li>2024 年 CapEx 高峰過後，2025 年驟降至 3.18 億（僅佔營收 3%）。若無新的大型投資項目，未來 CapEx 回報率可能因基期效應而遞減，增量營收貢獻將明顯縮小。</li><li>現金股利 8.62 元的可持續性高度取決於 EPS 能否維持 23 元以上。若 2026 年客戶 CAPEX 下調導致營收僅成長 15%，EPS 可能降至 18-20 元，屆時配息率將被迫壓縮。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li>FCF 25.9 億極度充裕，具備大幅提高配息率至 50-60% 或實施庫藏股的潛力，對股東回報的想像空間仍大。</li><li>CB 若全數轉換，利息費用節省將進一步推升 FCF，形成結構性的現金流改善。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>CapEx 效能已完美展現，但高基期後回報率遞減是自然規律。關鍵在於 CPO 量產投資是否啟動下一輪成長曲線。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>財務分析工具.py (capex_efficiency 6442)</li><li>FinMind TaiwanStockDividend</li><li>數據查詢日期：2026-05-04</li></ul>',23)])])}const u=e(l,[["render",i]]);export{c as __pageData,u as default};
